-- Пул резервных статей: используется когда RSS-источники недоступны.
-- ИИ-куратор перефразирует шаблон через polza.ai и публикует — текст всегда новый,
-- но структура и факты заданы заранее, поэтому контент гарантирован.
CREATE TABLE IF NOT EXISTS feed_demo_pool (
    id BIGSERIAL PRIMARY KEY,
    code VARCHAR(80) NOT NULL UNIQUE,
    category VARCHAR(40) NOT NULL,
    seed_title VARCHAR(400) NOT NULL,
    seed_summary TEXT NOT NULL,
    seed_facts TEXT NOT NULL,
    tags JSONB NOT NULL DEFAULT '[]'::jsonb,
    country VARCHAR(40) NOT NULL DEFAULT 'Россия',
    country_flag VARCHAR(8) NOT NULL DEFAULT '🇷🇺',
    use_count INTEGER NOT NULL DEFAULT 0,
    last_used_at TIMESTAMPTZ,
    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_demo_pool_use ON feed_demo_pool(use_count, last_used_at);

-- Метрики здоровья источников: счётчик подряд идущих ошибок + статус
ALTER TABLE feed_sources
  ADD COLUMN IF NOT EXISTS consecutive_errors INTEGER NOT NULL DEFAULT 0,
  ADD COLUMN IF NOT EXISTS auto_disabled_at TIMESTAMPTZ,
  ADD COLUMN IF NOT EXISTS last_success_at TIMESTAMPTZ;

-- Журнал health-monitor (для UI и алертов)
CREATE TABLE IF NOT EXISTS feed_health_events (
    id BIGSERIAL PRIMARY KEY,
    severity VARCHAR(20) NOT NULL,
    event_type VARCHAR(40) NOT NULL,
    title VARCHAR(300) NOT NULL,
    body TEXT,
    metadata JSONB,
    resolved_at TIMESTAMPTZ,
    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_health_unresolved ON feed_health_events(resolved_at, created_at DESC);

-- Заполняем пул резервных шаблонов (40 штук, по всем категориям)
